const SCH = { type:'object', additionalProperties:false, required:['t'], properties:{ t:{ type:'array', items:{ type:'object', additionalProperties:false, required:['r','jp'], properties:{ r:{type:'string'}, jp:{type:'string'} } } } } }
const CH=[]; for(let i=0;i<ITEMS.length;i+=25) CH.push(ITEMS.slice(i,i+25))
const POL=`各項目はエスペラント語根(r)・割当漢字(k)・PIV定義(g, エスペラント語のラテン的定義)。gを読んで、その語根の意味を表す【短い日本語の代表訳】を作れ。
- 15字以内。名詞は名詞形(「〜の」等にしない)。可能なら標準和名/標準訳語(動植物・医学・化学・数学等)。
- 割当漢字kも手掛かりにするが、訳はgの定義に忠実に。分類が分かれば【医】【植】等を先頭に付けてよい(任意)。
- 不明確でも最善の短い訳を返す。各項目: r(語根そのまま), jp(短い日本語訳)。`
phase('Translate')
const res = await parallel(CH.map((c,ci)=>()=> agent(`${POL}\n項目(JSON): ${JSON.stringify(c)}`, { label:`tr:${ci}`, phase:'Translate', schema:SCH }).then(r=>(r&&r.t)?r.t:[]) ))
const t = res.filter(Boolean).flat()
log(`翻訳 ${ITEMS.length} / 取得 ${t.length}`)
return { count: ITEMS.length, translations: t }